use super::{Lint, LintKind, Linter, SuggestionCollectionExt};
use crate::{CharStringExt, Document, Span, Token};

#[derive(Default)]
pub struct VerseVerb;

impl Linter for VerseVerb {
    fn lint(&mut self, document: &Document) -> Vec<Lint> {
        let tokens = document.get_tokens();
        let source = document.get_source();
        let mut lints = Vec::new();

        for (idx, token) in tokens.iter().enumerate() {
            if !token.kind.is_word() {
                continue;
            }

            let Some(form) = VerseForm::from_token(token, source) else {
                continue;
            };

            let prev = prev_word(tokens, idx);
            let prev_before_prev = prev.and_then(|prev_idx| prev_word(tokens, prev_idx));
            let next = next_word(tokens, idx);
            let next_after_next = next.and_then(|next_idx| next_word(tokens, next_idx));

            if !is_suspicious_context(
                form,
                tokens,
                source,
                prev,
                prev_before_prev,
                next,
                next_after_next,
            ) {
                continue;
            }

            let (span, suggestions) = if next.is_some_and(|next_idx| is_word(tokens, source, next_idx, "against")) {
                (
                    Span::new(token.span.start, tokens[next.unwrap()].span.end),
                    form.suggestions_without_against(),
                )
            } else {
                (token.span, form.suggestions())
            };

            lints.push(Lint {
                span,
                lint_kind: LintKind::Usage,
                suggestions: suggestions
                    .into_iter()
                    .to_replace_suggestions(span.get_content(source))
                    .collect(),
                message: "Use a standard verb such as `face`, `challenge`, or `play against` instead of treating `verse` or `versus` as a verb.".to_owned(),
                priority: 31,
            });
        }

        lints
    }

    fn description(&self) -> &str {
        "Flags `verse`, `verses`, `versed`, `versing`, and `vs` when they are used as verbs related to `versus`."
    }
}

#[derive(Clone, Copy)]
enum VerseForm {
    Base,
    ThirdPerson,
    Past,
    Progressive,
    Vs,
}

impl VerseForm {
    fn from_token(token: &Token, source: &[char]) -> Option<Self> {
        let chars = token.span.get_content(source);

        if chars.eq_ignore_ascii_case_str("verse") {
            Some(Self::Base)
        } else if chars.eq_ignore_ascii_case_str("verses") {
            Some(Self::ThirdPerson)
        } else if chars.eq_ignore_ascii_case_str("versed") {
            Some(Self::Past)
        } else if chars.eq_ignore_ascii_case_str("versing") {
            Some(Self::Progressive)
        } else if chars.eq_ignore_ascii_case_str("vs") {
            Some(Self::Vs)
        } else {
            None
        }
    }

    fn suggestions(self) -> &'static [&'static str] {
        match self {
            Self::Base | Self::Vs => &["face", "challenge", "play against", "compete against"],
            Self::ThirdPerson => &[
                "faces",
                "challenges",
                "plays against",
                "competes against",
                "versus",
            ],
            Self::Past => &[
                "faced",
                "challenged",
                "played against",
                "competed against",
            ],
            Self::Progressive => &[
                "facing",
                "challenging",
                "playing against",
                "competing against",
            ],
        }
    }

    fn suggestions_without_against(self) -> &'static [&'static str] {
        match self {
            Self::ThirdPerson => &["faces", "challenges", "plays against", "competes against"],
            _ => self.suggestions(),
        }
    }
}

fn is_suspicious_context(
    form: VerseForm,
    tokens: &[Token],
    source: &[char],
    prev: Option<usize>,
    prev_before_prev: Option<usize>,
    next: Option<usize>,
    next_after_next: Option<usize>,
) -> bool {
    if matches!(form, VerseForm::Past) && is_well_versed_context(tokens, source, prev) {
        return false;
    }

    let has_against_after = next.is_some_and(|idx| is_word(tokens, source, idx, "against"));
    let has_object_after = next.is_some_and(|idx| starts_object(tokens, source, idx));
    let has_only_object_after = next.is_some_and(|idx| is_word(tokens, source, idx, "only"))
        && next_after_next.is_some_and(|idx| starts_object(tokens, source, idx));
    let has_left_verb_cue = prev.is_some_and(|idx| is_left_verb_cue(tokens, source, idx));
    let has_left_subject = prev.is_some_and(|idx| is_subject_like(tokens, source, idx));
    let has_left_noun_phrase = prev.is_some_and(|idx| is_noun_phrase_head(tokens, idx));
    let has_left_multiword_noun_phrase = prev
        .zip(prev_before_prev)
        .is_some_and(|(prev, before)| is_multiword_noun_phrase_head(tokens, prev, before));

    match form {
        VerseForm::Progressive => has_left_verb_cue || has_left_subject || has_object_after,
        VerseForm::Past => (has_left_verb_cue || has_left_subject) && has_object_after,
        VerseForm::Base => {
            has_left_verb_cue
                || (has_against_after && (has_left_verb_cue || has_left_subject))
                || (has_object_after && (has_left_subject || has_left_multiword_noun_phrase))
        }
        VerseForm::ThirdPerson => {
            ((has_object_after || has_only_object_after) && (has_left_subject || has_left_noun_phrase))
                || (has_left_verb_cue && (has_object_after || has_only_object_after))
        }
        VerseForm::Vs => (has_left_verb_cue || is_left_adverbial_cue(tokens, source, prev)) && has_object_after,
    }
