fn is_left_adverbial_cue(tokens: &[Token], source: &[char], idx: Option<usize>) -> bool {
    idx.is_some_and(|idx| {
        ["never", "not", "n't", "just", "already"]
            .iter()
            .any(|word| tokens[idx].span.get_content(source).eq_ignore_ascii_case_str(word))
    })
}

fn is_subject_like(tokens: &[Token], source: &[char], idx: usize) -> bool {
    let kind = &tokens[idx].kind;

    kind.is_subject_pronoun()
        || kind.is_plural_noun()
        || (kind.is_oov() && tokens[idx].span.get_content(source).iter().any(|c| c.is_ascii_digit()))
}

fn is_noun_phrase_head(tokens: &[Token], idx: usize) -> bool {
    let kind = &tokens[idx].kind;

    (kind.is_noun() || kind.is_proper_noun() || kind.is_oov())
        && !kind.is_possessive_nominal()
